require "config.SeasonConfig"

local GUISeasonResult = class("", IGUILayout)

function GUISeasonResult:onLoad()
    --StaticImage
    self.ivLastHonorFlag = self:getChildWindow("LuckySkyHallSeasonResult-Last-Flag", GUIType.StaticImage)
    self.ivLastHonorIcon = self:getChildWindow("LuckySkyHallSeasonResult-Last-Icon", GUIType.StaticImage)
    self.ivCurHonorFlag = self:getChildWindow("LuckySkyHallSeasonResult-Cur-Flag", GUIType.StaticImage)
    self.ivCurHonorIcon = self:getChildWindow("LuckySkyHallSeasonResult-Cur-Icon", GUIType.StaticImage)

    --StaticText
    self.tvLastHonorScore = self:getChildWindow("LuckySkyHallSeasonResult-Last-Score-Text", GUIType.StaticText)
    self.tvLastHonorName = self:getChildWindow("LuckySkyHallSeasonResult-Last-Name-Text", GUIType.StaticText)
    self.tvLastHonorRank = self:getChildWindow("LuckySkyHallSeasonResult-Last-Rank-Text", GUIType.StaticText)
    self.tvCurHonorScore = self:getChildWindow("LuckySkyHallSeasonResult-Cur-Score-Text", GUIType.StaticText)
    self.tvCurHonorName = self:getChildWindow("LuckySkyHallSeasonResult-Cur-Name-Text", GUIType.StaticText)
    self.tvCurHonorRank = self:getChildWindow("LuckySkyHallSeasonResult-Cur-Rank-Text", GUIType.StaticText)

    self:getChildWindow("LuckySkyHallSeasonResult-Title-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.season.result.title.text"))
    self:getChildWindow("LuckySkyHallSeasonResult-Last-Title-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.last.season.title.text"))
    self:getChildWindow("LuckySkyHallSeasonResult-Cur-Title-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.cur.season.title.text"))

    self:getChildWindow("LuckySkyHallSeasonResult-Close", GUIType.Button):registerEvent(GUIEvent.ButtonClick, function()
        self:hide()
    end)
    self:registerDataCallBack("CurrentSeasonInfo", function(data)
        self:updateCurHonor(data)
    end, DataBuilderProcessor)
    self:registerDataCallBack("LastSeasonInfo", function(data)
        self:updateLastHonor(data)
    end, DataBuilderProcessor)
end

function GUISeasonResult:updateCurHonor(data)
    local honorId = data:getNumberParam("honorId")
    local rank = data:getNumberParam("rank")
    local honor = data:getNumberParam("honor")

    local setting = SeasonConfig:getSeasonByHonorId(honorId)
    if not setting then
        return
    end

    self.ivCurHonorFlag:SetImage(setting.flag)
    self.ivCurHonorIcon:SetImage(setting.icon)
    self.tvCurHonorName:SetText(Lang:getString(setting.name))
    self.tvCurHonorRank:SetText("No." .. rank)
    self.tvCurHonorScore:SetText(honor)
end

function GUISeasonResult:updateLastHonor(data)
    local honorId = data:getNumberParam("honorId")
    local rank = data:getNumberParam("rank")
    local honor = data:getNumberParam("honor")

    local setting = SeasonConfig:getSeasonByHonorId(honorId)
    if not setting then
        return
    end

    self.ivLastHonorFlag:SetImage(setting.flag)
    self.ivLastHonorIcon:SetImage(setting.icon)
    self.tvLastHonorName:SetText(Lang:getString(setting.name))
    self.tvLastHonorRank:SetText("No." .. rank)
    self.tvLastHonorScore:SetText(honor)

    self:show()
end

return GUISeasonResult